{"filter":false,"title":"tool_b2_step2.py","tooltip":"/evaluation/tool_b2_step2.py","undoManager":{"mark":0,"position":0,"stack":[[{"start":{"row":0,"column":0},"end":{"row":208,"column":0},"action":"insert","lines":["# evaluation/tool_b2_step2.py","from __future__ import annotations","","import json","import math","from dataclasses import dataclass","from pathlib import Path","from typing import Any, Dict, List, Sequence","","import pandas as pd","","from evaluation.loader import TrialRecord","from evaluation.llm_labeler_b2 import LLMLabelerB2, LabelerB2Config","from evaluation.text_normalize import normalize_text","","","def _load_deepdive_keys(categories_path: Path) -> List[str]:","    cfg = json.loads(categories_path.read_text(encoding=\"utf-8\"))","    return [c[\"key\"] for c in cfg[\"deepdive_categories\"]]","","","def _load_entropy_exclude(categories_path: Path) -> List[str]:","    cfg = json.loads(categories_path.read_text(encoding=\"utf-8\"))","    return list(cfg.get(\"entropy_exclude\", []))","","","def _normalized_entropy_from_counts(counts: Dict[str, int], keys: List[str]) -> float:","    \"\"\"","    counts: category -> count","    keys: entropy計算対象のカテゴリキー（Extras除外済みのリスト）","    \"\"\"","    vec = [int(counts.get(k, 0)) for k in keys]","    k = len(vec)","    if k <= 1:","        return 0.0","    total = sum(vec)","    if total <= 0:","        return 0.0","    ps = [v / total for v in vec if v > 0]","    h = -sum(p * math.log(p) for p in ps)","    h_max = math.log(k)","    return float(h / h_max) if h_max > 0 else 0.0","","","@dataclass","class ToolB2Step2Outputs:","    # sample_id × category_count（Extras含む）","    question_categories_df: pd.DataFrame","","    # sample_id × entropy 等（Extras除外で計算）","    question_entropy_df: pd.DataFrame","","    # sample_id × turn × question × category（詳細）","    question_detail_df: pd.DataFrame","","    report: Dict[str, Any]","","","def run_tool_b2_step2_question_distribution(","    trials: Sequence[TrialRecord],","    *,","    prompt_path: Path,","    categories_path: Path,","    outputs_dir: Path,","    temperature: float = 0.2,","    max_retries: int = 2,",") -> ToolB2Step2Outputs:","    \"\"\"","    Tool B2 Step2:","    - 質問文に深掘りカテゴリ(単一)を付与","    - sample_id単位にカテゴリ回数分布を集計","    - Extras除外で正規化エントロピーを算出","    \"\"\"","    outputs_dir.mkdir(parents=True, exist_ok=True)","    out_jsonl = outputs_dir / \"tool_b2_labels.jsonl\"","    err_jsonl = outputs_dir / \"tool_b2_errors.jsonl\"","","    keys_all = _load_deepdive_keys(categories_path)","    exclude = set(_load_entropy_exclude(categories_path))","    keys_entropy = [k for k in keys_all if k not in exclude]","","    labeler = LLMLabelerB2(","        LabelerB2Config(","            prompt_path=prompt_path,","            categories_path=categories_path,","            temperature=temperature,","            max_retries=max_retries,","        )","    )","","    detail_rows: List[Dict[str, Any]] = []","    count_map: Dict[str, Dict[str, int]] = {}","","    for t in trials:","        sample_id = t.zip_name","        meta = dict(t.meta or {})","        meta.update({\"run_id\": t.run_id})","","        if sample_id not in count_map:","            count_map[sample_id] = {k: 0 for k in keys_all}","","        # Step1で作った qa_pairs を使う（質問のみ見る）","        for p in t.qa_pairs:","            q = normalize_text(p.question) if p.question else \"\"","            if not q.strip():","                continue","","            out = labeler.label_deepdive_category(","                sample_id=sample_id,","                turn=int(p.turn),","                question_text=q,","                meta=meta,","                out_jsonl=out_jsonl,","                err_jsonl=err_jsonl,","            )","            if not out:","                continue","","            cat = out[\"category\"]","            rationale = out.get(\"rationale\", \"\")","","            if cat not in count_map[sample_id]:","                # ここに来るのは基本的に異常（カテゴリ定義外）","                continue","","            count_map[sample_id][cat] += 1","","            detail_rows.append(","                {","                    \"sample_id\": sample_id,","                    \"turn\": int(p.turn),","                    \"question\": q,","                    \"category\": cat,","                    \"rationale\": rationale,","                }","            )","","    # sample_id × category_count","    cat_rows: List[Dict[str, Any]] = []","    ent_rows: List[Dict[str, Any]] = []","","    for sample_id, counts in count_map.items():","        r = {\"sample_id\": sample_id}","        total_q = sum(int(counts.get(k, 0)) for k in keys_all)","        extras_q = int(counts.get(\"Extras\", 0))","","        for k in keys_all:","            r[k] = int(counts.get(k, 0))","        r[\"total_questions\"] = int(total_q)","        r[\"extras_questions\"] = int(extras_q)","        cat_rows.append(r)","","        # entropy（Extras除外）","        h = _normalized_entropy_from_counts(counts, keys_entropy)","","        # 補助：最大カテゴリ比率（Extras除外）","        total_non_extra = sum(int(counts.get(k, 0)) for k in keys_entropy)","        if total_non_extra > 0:","            max_count = max(int(counts.get(k, 0)) for k in keys_entropy)","            max_ratio = float(max_count / total_non_extra)","        else:","            max_ratio = 0.0","","        ent_rows.append(","            {","                \"sample_id\": sample_id,","                \"normalized_entropy_questions\": float(h),","                \"total_questions\": int(total_q),","                \"extras_questions\": int(extras_q),","                \"non_extras_questions\": int(total_non_extra),","                \"max_category_ratio\": float(max_ratio),","            }","        )","","    question_categories_df = pd.DataFrame(cat_rows)","    question_entropy_df = pd.DataFrame(ent_rows)","    question_detail_df = pd.DataFrame(detail_rows)","","    report = {","        \"tool\": \"tool_b2_question_validity_step2\",","        \"sample_id_policy\": \"zip_name\",","        \"target\": \"question texts only (from qa_pairs)\",","        \"deepdive_categories\": keys_all,","        \"entropy_exclude\": list(exclude),","        \"metrics\": {","            \"distribution\": \"counts per category\",","            \"primary\": \"normalized_entropy_questions (computed on categories excluding Extras)\",","            \"aux\": [\"max_category_ratio\", \"extras_questions\", \"total_questions\"],","        },","        \"llm\": {","            \"model\": \"MODEL_NAME from chains.py\",","            \"prompt\": str(prompt_path),","            \"categories\": str(categories_path),","            \"temperature\": float(temperature),","            \"max_retries\": int(max_retries),","        },","        \"outputs\": {","            \"labels_jsonl\": str(out_jsonl),","            \"errors_jsonl\": str(err_jsonl),","        },","    }","","    return ToolB2Step2Outputs(","        question_categories_df=question_categories_df,","        question_entropy_df=question_entropy_df,","        question_detail_df=question_detail_df,","        report=report,","    )",""],"id":1}]]},"ace":{"folds":[],"scrolltop":0,"scrollleft":0,"selection":{"start":{"row":8,"column":0},"end":{"row":8,"column":0},"isBackwards":false},"options":{"guessTabSize":true,"useWrapMode":false,"wrapToView":true},"firstLineState":0},"timestamp":1768886616398,"hash":"d8fcf89943c9d15fe4f788d75950314444e25c24"}